        { word: 'amṛtasya avyayasya ca', meaning: 'of the immortal and the imperishable / of what is deathless and inexhaustible' },
        { word: 'śāśvatasya ca dharmasya', meaning: 'and of the eternal dharma / of the everlasting righteous order' },
        { word: 'sukhasya ekāntikasya ca', meaning: 'and of absolute happiness / of undivided, unconditional bliss' }
